431		private calculateSeasonalComponent({
432			values,
433			period,
434			harmonics,
435		}: {
436			values: number[];
437			period: number;
438			harmonics: number;
439		}): number[] {
440			const n = values.length;
441			if (n < period) {
442				return new Array(n).fill(0) as number[];
443			}
444	
445			try {
446				const coefficients = MathematicalFunctions.fourierCoefficients({
447					values,
448					period,
449					harmonics,
450					precision: null,
451				});
452	
453				const seasonal = MathematicalFunctions.reconstructFourierSeries({
454					period,
455					harmonics,
456					a: coefficients.a,
457					b: coefficients.b,
458					length: n,
459				});
460	
461				return seasonal;
462			} catch (error) {
463				this.logger.error(
464					`Error extending seasonal component: ${(error as Error).message}`,
465					(error as Error).stack,
466				);
467				return values.map((_, index) => {
468					const cyclePosition = index % Math.max(1, Math.floor(period));
469					const seasonalIndex = Math.min(cyclePosition, values.length - 1);
470					return values[seasonalIndex] ? values[seasonalIndex] * 0.1 : 0;
471				});
472			}
473		}
