865	
866			const trendSlope = this.calculateTrendSlope({ trendComponent });
867	
868			if (growthRate > 0.2 || forecastAvg > historicalAvg * 1.2) {
869				return { trendingReason: 'Strong growth forecast', growthRate };
870			} else if (growthRate > 0.1 || forecastAvg > historicalAvg * 1.1) {
871				return { trendingReason: 'Moderate growth forecast', growthRate };
872			} else if (growthRate > 0 || trendSlope >= 0.05) {
873				return { trendingReason: 'Positive trend detected', growthRate };
874			} else {
875				return { trendingReason: 'Stable pattern', growthRate };
